// src/components/InternshipCard.jsx
import React from "react";
import "./InternshipCard.css";

const InternshipCard = ({
  internship,
  userRole,
  applicationStatus,
  onApply,
  onEdit,
  onDelete,
}) => {
  const {
    _id,
    title,
    company,
    location,
    stipend,
    duration,
    description,
    postedBy,
  } = internship;

  return (
    <div className="internship-card">
      <h2>{title}</h2>
      <p><strong>Company:</strong> {company}</p>
      <p><strong>Location:</strong> {location}</p>
      <p><strong>Duration:</strong> {duration}</p>
      <p><strong>Stipend:</strong> ₹{stipend}</p>
      <p className="description">{description}</p>
      <p className="posted-by">Posted by: {postedBy?.name || "N/A"}</p>

      <div className="card-actions">
        {userRole === "Student" && (
          <button
            className={`apply-btn ${
              applicationStatus !== "Not Applied" ? "applied" : ""
            }`}
            disabled={applicationStatus !== "Not Applied"}
            onClick={() => onApply(_id)}
          >
            {applicationStatus !== "Not Applied" ? applicationStatus : "Apply"}
          </button>
        )}

        {(userRole === "Admin" || userRole === "HR") && (
          <>
            <button className="edit-btn" onClick={() => onEdit(internship)}>
              Edit
            </button>
            {userRole === "Admin" && (
              <button className="delete-btn" onClick={() => onDelete(_id)}>
                Delete
              </button>
            )}
          </>
        )}
      </div>
    </div>
  );
};

export default InternshipCard;
